import numpy as np
from typing import Tuple, Dict

class MagicStateFidelity:
    T_STATE = np.array([1, np.exp(1j * np.pi / 4)]) / np.sqrt(2)
    PLUS_STATE = np.array([1, 1]) / np.sqrt(2)
    ZERO_STATE = np.array([1, 0])

    # Pauli matrices
    X = np.array([[0, 1], [1, 0]])
    Y = np.array([[0, -1j], [1j, 0]])
    Z = np.array([[1, 0], [0, -1]])
    I = np.array([[1, 0], [0, 1]])

    @staticmethod
    def fidelity(state1: np.ndarray, state2: np.ndarray) -> float:
        overlap = np.abs(np.vdot(state1, state2))
        return overlap ** 2

    @staticmethod
    def infidelity(state1: np.ndarray, state2: np.ndarray) -> float:
        return 1 - MagicStateFidelity.fidelity(state1, state2)

    @classmethod
    def depolarize(cls, state: np.ndarray, error_rate: float) -> np.ndarray:
        # Pure state to density matrix
        rho = np.outer(state, np.conj(state))

        # Depolarizing channel
        p = error_rate
        rho_X = cls.X @ rho @ cls.X
        rho_Y = cls.Y @ rho @ cls.Y
        rho_Z = cls.Z @ rho @ cls.Z

        return (1 - p) * rho + (p / 3) * (rho_X + rho_Y + rho_Z)

    @staticmethod
    def mixed_state_fidelity(rho: np.ndarray, target: np.ndarray) -> float:
        return np.real(np.conj(target) @ rho @ target)

    @classmethod
    def noisy_t_state(cls, error_rate: float) -> Tuple[np.ndarray, float]:
        rho = cls.depolarize(cls.T_STATE, error_rate)
        fid = cls.mixed_state_fidelity(rho, cls.T_STATE)
        return rho, fid

    @classmethod
    def distillation_output_fidelity(cls, input_fidelity: float,
                                      protocol: str = '15-to-1') -> float:
        eps_in = 1 - input_fidelity

        if protocol == '15-to-1':
            eps_out = min(1, 35 * eps_in ** 3)
        elif protocol == '7-to-1':
            eps_out = min(1, 7 * eps_in ** 2)
        else:
            raise ValueError(f"Unknown protocol: {protocol}")

        return 1 - eps_out
